import{_ as e,c as r,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Соглашение пользователя: Правила сервиса | OpenCodeDocs","description":"Ознакомьтесь с правилами использования сервиса OpenCodeDocs, правом собственности на интеллектуальную собственность и положениями об освобождении от ответственности, чётко определяя права и обязанности обеих сторон.","frontmatter":{"title":"Соглашение пользователя: Правила сервиса | OpenCodeDocs","sidebarTitle":"5 минут на ознакомление с правилами","subtitle":"Соглашение пользователя: Правила сервиса","description":"Ознакомьтесь с правилами использования сервиса OpenCodeDocs, правом собственности на интеллектуальную собственность и положениями об освобождении от ответственности, чётко определяя права и обязанности обеих сторон."},"headers":[],"relativePath":"ru/terms.md","filePath":"ru/terms.md"}'),o={name:"ru/terms.md"};function i(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="соглашение-о-предоставлении-пользовательского-сервиса" tabindex="-1">Соглашение о предоставлении пользовательского сервиса <a class="header-anchor" href="#соглашение-о-предоставлении-пользовательского-сервиса" aria-label="Permalink to &quot;Соглашение о предоставлении пользовательского сервиса&quot;">​</a></h1><p><strong>Дата последнего обновления</strong>: 2026-01-01<br><strong>Дата вступления в силу</strong>: 2026-01-01</p><p>Добро пожаловать в OpenCodeDocs! Перед использованием наших сервисов, пожалуйста, внимательно ознакомьтесь с настоящим соглашением о предоставлении пользовательского сервиса (далее — &quot;Соглашение&quot;). Использование наших сервисов означает ваше согласие на соблюдение условий настоящего Соглашения.</p><h2 id="_1-описание-сервиса" tabindex="-1">1. Описание сервиса <a class="header-anchor" href="#_1-описание-сервиса" aria-label="Permalink to &quot;1. Описание сервиса&quot;">​</a></h2><p>OpenCodeDocs — это открытая платформа, специализирующаяся на руководствах по использованию AI-инструментов, предоставляющая следующие услуги:</p><ul><li><strong>Содержание руководств</strong>: руководства по использованию открытых AI-инструментов (таких как Claude Code, Cursor, LangChain и др.)</li><li><strong>Проверка кода</strong>: автоматическая проверка работоспособности кода в руководствах на основе репозитория исходного кода</li><li><strong>Функции сообщества</strong>: пользователи могут участвовать в создании контента и обсуждениях через GitHub</li></ul><p>Мы оставляем за собой право в любое время изменять, приостанавливать или полностью или частично прекращать предоставление услуг без предварительного уведомления.</p><h2 id="_2-регистрация-и-управление-учетнои-записью" tabindex="-1">2. Регистрация и управление учётной записью <a class="header-anchor" href="#_2-регистрация-и-управление-учетнои-записью" aria-label="Permalink to &quot;2. Регистрация и управление учётной записью&quot;">​</a></h2><h3 id="условия-регистрации" tabindex="-1">Условия регистрации <a class="header-anchor" href="#условия-регистрации" aria-label="Permalink to &quot;Условия регистрации&quot;">​</a></h3><ul><li>Вы должны быть старше 16 лет (или достигнуть законного возраста в вашем регионе)</li><li>Предоставить правдивую и точную информацию при регистрации</li><li>Каждый пользователь может зарегистрировать только одну учётную запись</li></ul><h3 id="безопасность-учетнои-записи" tabindex="-1">Безопасность учётной записи <a class="header-anchor" href="#безопасность-учетнои-записи" aria-label="Permalink to &quot;Безопасность учётной записи&quot;">​</a></h3><ul><li>Вы несёте ответственность за сохранность данных учётной записи, запрещается делиться ими с другими лицами</li><li>Если вы обнаружите несанкционированный доступ к учётной записи, пожалуйста, немедленно свяжитесь с нами</li><li>Потери, вызванные неудовлетворительным управлением учётной записью, вы несёте самостоятельно</li></ul><h3 id="удаление-учетнои-записи" tabindex="-1">Удаление учётной записи <a class="header-anchor" href="#удаление-учетнои-записи" aria-label="Permalink to &quot;Удаление учётной записи&quot;">​</a></h3><p>Вы можете в любое время подать заявку на удаление учётной записи. После удаления ваши персональные данные будут удалены в течение 30 дней, но общедоступный контент может оставаться.</p><h2 id="_3-нормы-поведения-пользователя" tabindex="-1">3. Нормы поведения пользователя <a class="header-anchor" href="#_3-нормы-поведения-пользователя" aria-label="Permalink to &quot;3. Нормы поведения пользователя&quot;">​</a></h2><p>При использовании данной платформы вы соглашаетесь не заниматься следующими действиями:</p><ul><li>Публикация незаконного, вредоносного, угрожающего, оскорбительного, клеветнического или нарушающего права контента</li><li>Притворство другими людьми или ложное указание личности</li><li>Несанкционированный доступ к учётным записям или системам других пользователей</li><li>Помехи или разрушение нормальной работы сервиса</li><li>Массовый сбор контента с помощью автоматизированных инструментов (за исключением разумного использования API)</li><li>Использование содержания руководств в коммерческих целях без соблюдения лицензионного соглашения</li></ul><h2 id="_4-интеллектуальная-собственность" tabindex="-1">4. Интеллектуальная собственность <a class="header-anchor" href="#_4-интеллектуальная-собственность" aria-label="Permalink to &quot;4. Интеллектуальная собственность&quot;">​</a></h2><h3 id="описание-лицензии-с-открытым-исходным-кодом" tabindex="-1">Описание лицензий с открытым исходным кодом <a class="header-anchor" href="#описание-лицензии-с-открытым-исходным-кодом" aria-label="Permalink to &quot;Описание лицензий с открытым исходным кодом&quot;">​</a></h3><ul><li><strong>Содержание руководств</strong>: используется лицензия <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a>, разрешающая некоммерческое распространение и адаптацию, но с обязательным указанием авторства и распространением на тех же условиях</li><li><strong>Конструкция сайта</strong>: данный проект построен на основе <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>, следует лицензии MIT</li><li><strong>Вклады пользователей</strong>: предоставляемый вами контент по умолчанию лицензируется платформе для использования при соблюдении вышеуказанных соглашений</li></ul><p>Товарные знаки, логотипы и другие идентификаторы бренда OpenCodeDocs защищены законом, и их использование без авторизации запрещено.</p><h2 id="_5-положения-об-освобождении-от-ответственности" tabindex="-1">5. Положения об освобождении от ответственности <a class="header-anchor" href="#_5-положения-об-освобождении-от-ответственности" aria-label="Permalink to &quot;5. Положения об освобождении от ответственности&quot;">​</a></h2><ul><li><strong>Прерывание сервиса</strong>: мы не гарантируем непрерывность или отсутствие ошибок в сервисе. Мы не несём ответственности за прерывание сервиса, вызванное обслуживанием, обновлением или форс-мажором</li><li><strong>Точность контента</strong>: содержание руководств предоставляется только для справки, мы не гарантируем его доступность во всех средах</li><li><strong>Риски использования кода</strong>: вы несёте риск запуска кода из руководств, рекомендуем тестировать в изолированной среде</li><li><strong>Ссылки на третьих лиц</strong>: на этом сайте могут содержаться ссылки на веб-сайты третьих лиц, мы не несем ответственности за их содержание</li></ul><h2 id="_6-изменение-соглашения" tabindex="-1">6. Изменение соглашения <a class="header-anchor" href="#_6-изменение-соглашения" aria-label="Permalink to &quot;6. Изменение соглашения&quot;">​</a></h2><p>Мы можем время от времени изменять настоящее Соглашение. Изменённое соглашение будет опубликовано на веб-сайте, и мы уведомим вас следующими способами:</p><ul><li>Объявление на заметном месте веб-сайта</li><li>Отправка уведомления по электронной почте регистрации (если применимо)</li></ul><p>Продолжение использования наших сервисов означает ваше принятие изменённого Соглашения. Если вы не согласны с изменениями, пожалуйста, прекратите использование сервиса.</p><h2 id="_7-урегулирование-споров" tabindex="-1">7. Урегулирование споров <a class="header-anchor" href="#_7-урегулирование-споров" aria-label="Permalink to &quot;7. Урегулирование споров&quot;">​</a></h2><ul><li><strong>Применимое право</strong>: настоящее Соглашение регулируется законами Китайской Народной Республики</li><li><strong>Урегулирование споров</strong>: стороны должны дружелюбно урегулировать споры через переговоры; если переговоры не удастся, любая из сторон может подать иск в народный суд с юрисдикцией по месту нахождения ответчика</li></ul><h2 id="_8-контактная-информация" tabindex="-1">8. Контактная информация <a class="header-anchor" href="#_8-контактная-информация" aria-label="Permalink to &quot;8. Контактная информация&quot;">​</a></h2><p>Если у вас есть какие-либо вопросы по поводу настоящего Соглашения, пожалуйста, свяжитесь с:</p><ul><li><strong>Электронная почта</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const p=e(o,[["render",i]]);export{g as __pageData,p as default};
